// Parse Twilio status callback
var data = $input.first().json;
var body = data.body || data;

var callSid = String(body.CallSid || '').replace(/[^a-zA-Z0-9]/g, '').substring(0, 34);
var callStatus = String(body.CallStatus || '').replace(/[^a-z-]/gi, '').substring(0, 30);
var callDuration = parseInt(body.CallDuration || body.Duration || 0);
var from = String(body.From || '').replace(/[^+0-9]/g, '').substring(0, 16);
var to = String(body.To || '').replace(/[^+0-9]/g, '').substring(0, 16);

// Only process completed calls
if (callStatus !== 'completed' && callStatus !== 'busy' && callStatus !== 'no-answer' && callStatus !== 'failed') {
  return [{ json: { skip: true, callStatus } }];
}

// Format duration
var min = Math.floor(callDuration / 60);
var sec = callDuration % 60;
var durationStr = min > 0 ? (min + 'min ' + sec + 's') : (sec + 's');

return [{ json: {
  skip: false,
  callSid, callStatus, callDuration, durationStr, from, to
}}];

