={{ (function() {
  var d = $input.first().json;
  var sid = d.callSid;
  var from9 = (d.from || '').replace(/[^0-9]/g, '').slice(-9);

  return "WITH chat AS ("
    + "SELECT session_id, message, created_at FROM n8n_chat_histories "
    + "WHERE session_id = '" + sid + "' ORDER BY created_at ASC LIMIT 20"
    + "), lead_check AS ("
    + "SELECT id, nom, prenom, telephone, source, statut, date_entretien, created_at "
    + "FROM leads WHERE telephone LIKE '%" + from9 + "%' "
    + "ORDER BY created_at DESC LIMIT 1"
    + ") "
    + "SELECT 'chat' as _type, message::text as data, created_at, NULL as nom, NULL as prenom, NULL as telephone, NULL as source, NULL as statut, NULL as lead_id, NULL as date_entretien FROM chat "
    + "UNION ALL "
    + "SELECT 'lead', NULL, created_at, nom, prenom, telephone, source, statut, id::text, date_entretien FROM lead_check";
})() }}

