// Build Telegram summary + SMS avis data
var statusData = $('02. Parse Status').first().json;
var rows = $('05. Query Conversation + Lead').all();

var messages = [];
var lead = null;

for (var i = 0; i < rows.length; i++) {
  var r = rows[i].json || rows[i];
  if (r._type === 'chat' && r.data) {
    try {
      var msg = typeof r.data === 'string' ? JSON.parse(r.data) : r.data;
      messages.push(msg);
    } catch(e) {
      messages.push({ type: 'unknown', content: String(r.data).substring(0, 200) });
    }
  } else if (r._type === 'lead') {
    lead = { id: r.lead_id, nom: r.nom, prenom: r.prenom, telephone: r.telephone, source: r.source, statut: r.statut, dateEntretien: r.date_entretien };
  }
}

// Build conversation summary
var convSummary = '';
var exchanges = 0;
for (var j = 0; j < messages.length; j++) {
  var m = messages[j];
  var role = '';
  var content = '';
  if (m.type === 'human' || m.role === 'human' || m.role === 'user') {
    role = '👤 Client';
    content = m.content || m.text || m.data?.content || '';
  } else if (m.type === 'ai' || m.role === 'ai' || m.role === 'assistant') {
    role = '🤖 Agent';
    content = m.content || m.text || m.data?.content || '';
    exchanges++;
  } else {
    continue;
  }
  if (content) {
    convSummary += role + ': ' + String(content).substring(0, 150) + '\n';
  }
}

// Status emoji
var statusEmoji = '✅';
if (statusData.callStatus === 'busy') statusEmoji = '📵';
if (statusData.callStatus === 'no-answer') statusEmoji = '📭';
if (statusData.callStatus === 'failed') statusEmoji = '❌';

// Generate avis token
var avisToken = require('crypto').randomBytes(16).toString('hex');
var leadId = lead ? lead.id : null;
var leadNom = lead ? ((lead.prenom || '') + ' ' + (lead.nom || '')).trim() : '';
var shouldSendSms = statusData.callStatus === 'completed' && statusData.callDuration > 30 && statusData.from;

// Build message
var msg = '📞 Résumé d\'appel ' + statusEmoji + '\n\n';
msg += '📱 De: ' + (statusData.from || 'inconnu') + '\n';
msg += '⏱️ Durée: ' + statusData.durationStr + '\n';
msg += '💬 Échanges: ' + exchanges + '\n\n';

// Lead info
if (lead && lead.nom) {
  var leadName = ((lead.prenom || '') + ' ' + (lead.nom || '')).trim();
  var isNew = lead.source && (lead.source.indexOf('telephone') >= 0);
  msg += '👤 Lead: ' + leadName + (isNew ? ' (nouveau ✨)' : '') + '\n';
  if (lead.dateEntretien) {
    msg += '📅 RDV: ' + new Date(lead.dateEntretien).toLocaleString('fr-FR', {timeZone: 'Europe/Paris'}) + '\n';
  }
  msg += '\n';
} else {
  msg += '👤 Lead: non créé\n\n';
}

// Conversation
if (convSummary) {
  msg += '💬 Conversation:\n' + convSummary.substring(0, 800) + '\n';
}

if (shouldSendSms) {
  msg += '\n📩 SMS avis envoyé au client';
}

msg += '\n⏰ ' + new Date().toLocaleString('fr-FR', {timeZone: 'Europe/Paris'});

return [{ json: {
  telegramMessage: msg,
  shouldSendSms: shouldSendSms,
  avisToken: avisToken,
  leadId: leadId,
  leadNom: leadNom,
  from: statusData.from,
  to: statusData.to
}}];

var d = $('06. Build Summary').first().json;
var to9 = (d.to || '').replace(/[^0-9]/g, '').slice(-9);

// Find tenant_id from the called number
var tenantQuery = "SELECT tenant_id::text, company_name FROM twilio_configs WHERE phone_number LIKE '%" + to9 + "%' LIMIT 1";

var avisUrl = 'https://demo.talosprimes.com/avis?token=' + d.avisToken + '&tel=' + encodeURIComponent(d.from);

var smsMessage = 'Merci pour votre appel ! Votre avis compte pour nous. '
  + 'Donnez-nous votre note en 30 secondes : ' + avisUrl;

return [{ json: {
  phoneNumber: d.from,
  message: smsMessage,
  avisToken: d.avisToken,
  avisUrl: avisUrl,
  leadId: d.leadId,
  to: d.to,
  tenantQuery: tenantQuery
}}];

